const http = require('http');
const input = $input.first().json;
const litellmHost = input.litellmHost;
const litellmPort = parseInt(input.litellmPort, 10);
const litellmApiKey = input.litellmApiKey || '';
const fullOutput = input.aggregatedOutput || input.mcpOutput || '';
const truncated = fullOutput.length > 3000 ? fullOutput.substring(0, 3000) + '\n[... truncated ...]' : fullOutput;
const systemPrompt = input.aiPrompt || 'Analyze this OpenShift output. Provide: 1) HTML summary table of key data, 2) Health verdict (Healthy/Warning/Critical) with color, 3) Recommendations. Use inline CSS, Red Hat style (#DC382D, #151515).';
const requestBody = JSON.stringify({
  model: 'granite',
  messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: truncated }],
  temperature: 0.3, max_tokens: 2048
});
return new Promise((resolve, reject) => {
  const req = http.request({
    hostname: litellmHost, port: litellmPort, path: '/v1/chat/completions', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + litellmApiKey, 'Content-Length': Buffer.byteLength(requestBody) }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        let rawAI = parsed.choices?.[0]?.message?.content || 'AI analysis unavailable';
        rawAI = rawAI.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
        const aiAnalysis = rawAI.length > 1800 ? rawAI.substring(0, 1800) + '
[... truncated ...]' : rawAI;
        resolve([{ json: { ...input, aiAnalysis, aiModel: parsed.model || 'granite' } }]);
      } catch (e) { resolve([{ json: { ...input, aiAnalysis: 'AI failed: ' + e.message, aiModel: 'error' } }]); }
    });
  });
  req.on('error', (e) => { resolve([{ json: { ...input, aiAnalysis: 'AI unreachable: ' + e.message, aiModel: 'unreachable' } }]); });
  req.write(requestBody);
  req.end();
});

